    private void btnGuardarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnGuardarActionPerformed
        // TODO add your handling code here:
        if (txtTitulo.getText().isEmpty() ||
            txtAutor.getText().isEmpty() ||
            txtEditora.getText().isEmpty() ||
            txtIdioma.getText().isEmpty() ||
            txtPagina.getText().isEmpty() ||
            txtQtd.getText().isEmpty() ||
            jDData.getDate() == null ||
            jCGenero.getSelectedItem() == null) {

            JOptionPane.showMessageDialog(null, 
            "Preencha todos os campos obrigatórios!");
        } else {
            Livro l = new Livro();
            l.setAno_publicacao(jYAno.getYear());
            l.setAutor(txtAutor.getText());
            l.setData_cadastro(new java.sql.Date(jDData.getDate().getTime()));
            l.setEditora(txtEditora.getText());
            l.setGenero((String) jCGenero.getSelectedItem());
            l.setIdioma(txtIdioma.getText());
            l.setPaginas(Integer.parseInt(txtPagina.getText()));
            l.setQuantidade(Integer.parseInt(txtQtd.getText()));
            l.setTitulo(txtTitulo.getText());
            try {
                LivroDAO dao = new LivroDAO();
                dao.Salvar(l);
            } catch (ClassNotFoundException ex) {
                Logger.getLogger(Cadastro_Livro.class.getName()).log(Level.SEVERE, null, ex);
            }
        }
    }//GEN-LAST:event_btnGuardarActionPerformed

